var getProbability = function(balls) {
    const k = balls.length;
    const pre_sum = [0];
    for(let b of balls) pre_sum.push(pre_sum[pre_sum.length - 1] + b);

    const dp = new Array(50).fill(0).map(() => new Array(50).fill(0).map(() => new Array(50).fill(0)));
    dp[0][0][0] = 1;
    for(let i = 0; i < k; ++i){
        for(let j = i; j >= 0; --j){
            for(let x = pre_sum[i+1]; x >= 0; --x){
                for(let y = pre_sum[i+1] - x; y >= 0; --y){
                    if (x + y <= balls[i]){
                        for(let d = Math.max(0, balls[i] - 2 * y); d <= x; ++d){
                            let tmp = 1;
                            for(let z = 1; z <= d; ++z) tmp *= x + y + 1 - z, tmp /= z;
                            for(let z = 1; z <= y; ++z) tmp *= x + y + d + 1 - z, tmp /= z;
                            for(let z = 1; z <= balls[i] - y - y - d; ++z) tmp *= x + y + d + 1 - z, tmp /= z;
                            dp[i+1][j+1][x+d] += dp[i][j][x] * tmp;
                            dp[i+1][j][x+d] += dp[i][j][x] * tmp;
                        }
                    }
                }
            }
        }
    }

    const sum_ = balls.reduce((acc, cur) => acc + cur);
    return (dp[k][k>>1][sum_>>1] - (1e-5 > dp[k][k>>1][sum_>>1])) / (sum_ % 2 ? 1 : (1<<(sum_>>1)));
};
