    ```java
class Solution {
    double[][][] dp = new double[50][50][50];
    public double getProbability(int[] balls) {
        int sum = 0, k = balls.length;
        for(int b : balls) sum += b;  
        int[] preSum = new int[k+1];
        for(int i = 0; i < k; i++) preSum[i+1] = preSum[i] + balls[i];

        for(int i = 0; i < 50; i++)
            for(int j = 0; j < 50; j++)
                for(int x = 0; x < 50; x++)
                    dp[i][j][x] = 0;

        dp[0][0][0] = 1;
        for(int i = 0; i < k; ++i) {
            for(int j = i; j >= 0; --j) {
                for(int x = preSum[i+1]; x >= 0; --x) {
                    for (int y = preSum[i + 1] - x; y >= 0; --y) {
                        if (x + y <= balls[i]) {
                            for (int d = Math.max(0, balls[i] - 2 * y); d <= x; ++d) {
                                double tmp = 1;
                                for (int z = 1; z <= d; ++z) tmp *= (x + y + 1 - z) / z;
                                for (int z = 1; z <= y; ++z) tmp *= (x + y + d + 1 - z) / z;
                                for (int z = 1; z <= balls[i] - y - y - d; ++z) tmp *= (x + y + d + 1 - z) / z;
                                dp[i + 1][j + 1][x + d] += dp[i][j][x] * tmp;
                                dp[i + 1][j][x + d] += dp[i][j][x] * tmp;
                            }
                        }
                    }
                }
            }
        }

        return (dp[k][k >> 1][sum >> 1] - (1e-5 > dp[k][k >> 1][sum >> 1])) / (sum % 2 != 0 ? 1 : (1 << (sum >> 1)));
    }
}
```


